#include <iostream>
using namespace std;

int main() {
    int choice;

    do {
        cout << "\n--- Menu ---" << endl;
        cout << "1. Say Hello" << endl;
        cout << "2. Say Goodbye" << endl;
        cout << "3. Exit" << endl;
        cout << "Choice: ";
        cin >> choice;

        switch (choice) {
            case 1: cout << "Hello!" << endl; break;
            case 2: cout << "Goodbye!" << endl; break;
            case 3: cout << "Exiting..." << endl; break;
            default: cout << "Invalid choice." << endl;
        }
    } while (choice != 3);

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int marks[] = {85, 92, 78, 95, 88};

    int total = 0;
    for (auto m : marks) {
        total += m;
    }

    cout << "Total: " << total << endl;
    cout << "Average: " << (double)total / 5 << endl;

    // Modify using reference
    for (auto& m : marks) {
        m += 5;  // Add 5 grace marks
    }

    cout << "After grace marks: ";
    for (auto m : marks) {
        cout << m << " ";
    }
    cout << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int n = 5;

    // Right triangle
    cout << "Right Triangle:" << endl;
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= i; j++) {
            cout << "* ";
        }
        cout << endl;
    }

    cout << endl;

    // Pyramid
    cout << "Pyramid:" << endl;
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n - i; j++) {
            cout << " ";
        }
        for (int j = 1; j <= 2 * i - 1; j++) {
            cout << "*";
        }
        cout << endl;
    }

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int n = 5;

    // Floyd's Triangle
    cout << "Floyd's Triangle:" << endl;
    int num = 1;
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= i; j++) {
            cout << num++ << " ";
        }
        cout << endl;
    }

    cout << endl;

    // Pascal's Triangle
    cout << "Pascal's Triangle:" << endl;
    for (int i = 0; i < n; i++) {
        int val = 1;
        for (int j = 0; j <= i; j++) {
            cout << val << " ";
            val = val * (i - j) / (j + 1);
        }
        cout << endl;
    }

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int n = 5;

    // Upper half (rows 1 to n)
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n - i; j++) cout << " ";
        for (int j = 1; j <= 2 * i - 1; j++) cout << "*";
        cout << endl;
    }

    // Lower half (rows n-1 to 1)
    for (int i = n - 1; i >= 1; i--) {
        for (int j = 1; j <= n - i; j++) cout << " ";
        for (int j = 1; j <= 2 * i - 1; j++) cout << "*";
        cout << endl;
    }

    return 0;
}

