int main() {
    int a, b;
    cout << "Enter two numbers: ";
    cin >> a >> b;
    int origA = a, origB = b;
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    cout << "GCD of " << origA << " and " << origB << ": " << a << endl;
    return 0;
}

#include <iostream>
#include <cmath>
using namespace std;
int main() {
    int n;
    cout << "Enter a number: ";
    cin >> n;
    int digits = 0, temp = n;
    while (temp > 0) { digits++; temp /= 10; }
    int sum = 0;
    temp = n;
    while (temp > 0) {
        int d = temp % 10;
        sum += pow(d, digits);
        temp /= 10;
    }
    cout << n << (sum == n ? " is" : " is not") << " an Armstrong number" << endl;
    return 0;
}
